class Solution {
public:
    string baseNeg2(int n) {
        if (n == 0) return "0";
        string res = "";
        while (n > 0) {
            res = (n & 1 ? "1" : "0") + res;
            n = (n + 1) / 2;
        }
        return res;
    }
};
```

